/**
 * Detect the error-as-response shapes that runApiAgentLoop returns on abort, timeout, or upstream failure. The loop converts thrown errors into `{response: 'Error: ...', toolCalls, steps}` for most streaming failures, and returns `[Timeout — ran out of time]` when the internal deadline fires. Synthesis must treat these as failures, not successful completions.
 */
// @kern-source: agent-synthesis:244
function isAgentLoopErrorResponse(response: string): boolean {
  if (!response) {
    return true;
  }
  const t = response.trimStart();
  if (t.startsWith('Error:')) {
    return true;
  }
  if (t.startsWith('[Timeout')) {
    return true;
  }
  return false;
}

/**
 * Run a synthesis pass on the winner's worktree using the elevated-loser-insights prompt. Re-invokes the winner via runApiAgentLoop with full tool access against the worktree the winner already edited, then captures the new diff against baseSha. Falls back gracefully in FIVE failure modes: (a) no losers → skipped; (b) signal aborted before call → ok=false; (c) runApiAgentLoop throws → ok=false; (d) runApiAgentLoop returns error-as-response shape → ok=false; (e) signal aborted during call → ok=false (checked post-return); (f) worktreeChangedDiff throws OR returns empty when original was non-empty → ok=false (corruption signal). In every failure mode synthesizedDiff is the original winnerDiff so the caller always has a safe value to surface. Used by AgentTeam.runAgentTeam in the CLI handler to mitigate RT-25 winner-refines blind spot.
 */
// @kern-source: agent-synthesis:256
export async function runAgentTeamSynthesis(opts: AgentSynthesisOptions): Promise<AgentSynthesisResult> {
  if (opts.losers.length === 0) {
    return {
      ok: true,
      synthesizedDiff: opts.winnerDiff,
      changed: false,
      error: null,
      responseExcerpt: '',
      skipped: true,
    };
  }
  // Pre-call abort check — if the caller already cancelled, don't even start.
  if (opts.signal?.aborted) {
    return {
      ok: false,
      synthesizedDiff: opts.winnerDiff,
      changed: false,
      error: 'Aborted before synthesis started',
      responseExcerpt: '',
      skipped: false,
    };
  }
  const prompt = buildAgentSynthesisPrompt({
    task: opts.task,
    winnerEngineId: opts.winnerEngineId,
    winnerDiff: opts.winnerDiff,
    losers: opts.losers,
  });
  try {
    const result = await runApiAgentLoop({
      api: opts.winnerApi,
      prompt,
      systemPrompt: opts.systemPrompt,
      cwd: opts.winnerWorktreePath,
      timeout: opts.timeout,
      signal: opts.signal,
      maxSteps: opts.maxSteps ?? 6,
      heavyToolSemaphore: opts.heavyToolSemaphore,
      onChunk: opts.onChunk,
      onToolCall: opts.onToolCall,
    });
    // Post-call abort check — if the caller cancelled mid-loop, runApiAgentLoop
    // may have returned a partial result. Discard it unconditionally.
    if (opts.signal?.aborted) {
      return {
        ok: false,
        synthesizedDiff: opts.winnerDiff,
        changed: false,
        error: 'Aborted during synthesis',
        responseExcerpt: result.response.slice(0, 400),
        skipped: false,
      };
    }
    // Detect error-as-response shape from runApiAgentLoop (it catches stream
    // errors and returns them as a "response" string rather than throwing).
    if (isAgentLoopErrorResponse(result.response)) {
      return {
        ok: false,
        synthesizedDiff: opts.winnerDiff,
        changed: false,
        error: `Synthesis loop reported error: ${result.response.slice(0, 200)}`,
        responseExcerpt: result.response.slice(0, 400),
        skipped: false,
      };
    }
    // Recompute diff against original baseSha — captures ORIGINAL winner
    // work AND synthesis refinement edits as one patch.
    let newDiff = '';
    try {
      newDiff = worktreeChangedDiff(opts.winnerWorktreePath, opts.baseSha);
    } catch (e) {
      return {
        ok: false,
        synthesizedDiff: opts.winnerDiff,
        changed: false,
        error: `Failed to recompute synthesized diff: ${e instanceof Error ? e.message : String(e)}`,
        responseExcerpt: result.response.slice(0, 400),
        skipped: false,
      };
    }
    // Corruption signal: worktreeChangedDiff silently returns '' on git
    // errors (e.g. corrupted index, broken worktree state). If the
    // pre-synthesis winner had a non-empty diff and we now get an empty
    // one, something broke — fall back rather than surface an empty patch
    // as "successful synthesis".
    if (opts.winnerDiff.trim() && !newDiff.trim()) {
      return {
        ok: false,
        synthesizedDiff: opts.winnerDiff,
        changed: false,
        error: 'Recomputed diff is empty but pre-synthesis winner had content — possible worktree corruption',
        responseExcerpt: result.response.slice(0, 400),
        skipped: false,
      };
    }
    const changed = newDiff.trim() !== opts.winnerDiff.trim();
    return {
      ok: true,
      synthesizedDiff: newDiff,
      changed,
      error: null,
      responseExcerpt: result.response.slice(0, 400),
      skipped: false,
    };
  } catch (err) {
    return {
      ok: false,
      synthesizedDiff: opts.winnerDiff,
      changed: false,
      error: err instanceof Error ? err.message : String(err),
      responseExcerpt: '',
      skipped: false,
    };
  }
}

